import{_ as n,o as i,c as a,a4 as t}from"./chunks/framework.D-fxZFZW.js";const p=JSON.parse('{"title":"ADR-006: Informational perf bench + skippable ceiling","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-006-informational-perf-bench.md","filePath":"reference/decisions/ADR-006-informational-perf-bench.md"}'),o={name:"reference/decisions/ADR-006-informational-perf-bench.md"};function r(s,e,l,c,d,h){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-006-informational-perf-bench-skippable-ceiling" tabindex="-1">ADR-006: Informational perf bench + skippable ceiling <a class="header-anchor" href="#adr-006-informational-perf-bench-skippable-ceiling" aria-label="Permalink to &quot;ADR-006: Informational perf bench + skippable ceiling&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-10 (non-functional), resolving RD-09 DEF-4</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RD-10 sets a frame-budget target: composing + diff-serializing a 200×50 frame should have a median ≤ 16 ms. But wall-clock timing is environment-sensitive — CI runners are noisy and shared, and contributor machines vary widely. A hard timing gate in CI would flake; no timing check at all would let regressions slip.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-hard-fail-the-16-ms-budget-in-ci" tabindex="-1">Option A: Hard-fail the 16 ms budget in CI <a class="header-anchor" href="#option-a-hard-fail-the-16-ms-budget-in-ci" aria-label="Permalink to &quot;Option A: Hard-fail the 16 ms budget in CI&quot;">​</a></h3><ul><li><strong>Pros</strong>: Strongest enforcement.</li><li><strong>Cons</strong>: Flaky on shared/throttled runners; erodes trust in the suite.</li></ul><h3 id="option-b-regression-vs-stored-baseline-in-ci" tabindex="-1">Option B: Regression-vs-stored-baseline in CI <a class="header-anchor" href="#option-b-regression-vs-stored-baseline-in-ci" aria-label="Permalink to &quot;Option B: Regression-vs-stored-baseline in CI&quot;">​</a></h3><ul><li><strong>Pros</strong>: Adapts to the runner.</li><li><strong>Cons</strong>: Needs a stored baseline + tuning; heavy for a foundation library.</li></ul><h3 id="option-c-informational-bench-a-ceiling-test-that-asserts-off-ci-only" tabindex="-1">Option C: Informational bench + a ceiling test that asserts off-CI only <a class="header-anchor" href="#option-c-informational-bench-a-ceiling-test-that-asserts-off-ci-only" aria-label="Permalink to &quot;Option C: Informational bench + a ceiling test that asserts off-CI only&quot;">​</a></h3><ul><li><strong>Pros</strong>: Real assertion on capable dev hardware; CI records numbers informationally; an opt-out (<code>TUI_SKIP_PERF</code>) covers slow local machines.</li><li><strong>Cons</strong>: No hard CI gate on timing (accepted — timing is environment-sensitive).</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option C — <code>npm run bench</code> prints median/p95 informationally, and <code>test/perf-budget.spec.test.ts</code> asserts the 16 ms median <strong>off-CI only</strong>, skipping its hard assertion under <code>CI</code> or <code>TUI_SKIP_PERF</code>.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>This mirrors RD-09&#39;s stance: deterministic evidence (byte-proportionality, size-independence) is always asserted, while wall-clock timing stays informational under CI. Off-CI on capable hardware the ceiling is a real gate; under CI the bench step tracks regressions without flaking. The detection-budget test follows the same skippable-timing rule. This resolves RD-09 DEF-4.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>A real local perf gate without CI flake; regression numbers still tracked in CI.</li><li>Byte-proportionality / size-independence remain deterministic, always-on oracles.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>No hard CI failure purely on a timing regression (caught off-CI or by inspecting the informational numbers).</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A slow regression could pass unnoticed if no one runs the bench — mitigated by the informational CI bench step printing numbers every run.</li></ul>',22)])])}const f=n(o,[["render",r]]);export{p as __pageData,f as default};
